def test_ayesha_sl_report():
    """Ayesha (MBD4-LOF + TP53-LOF) should get VALIDATED cytidine_analogs."""
    response = client.post("/api/v1/patient/sl_report", json={
        "patient_id": "ayesha_001",
        "mutations": [
            {"gene": "MBD4", "variant": "c.1562delG", "consequence": "frameshift"},
            {"gene": "TP53", "variant": "R175H", "consequence": "missense"}
        ],
        "cancer_type": "ovarian_cancer"
    })
    assert response.status_code == 200
    report = response.json()
    assert report["ruo"] is True
